 54→
 55→public class CachingKeyValueStore
 56→    extends WrappedStateStore<KeyValueStore<Bytes, byte[]>, byte[], byte[]>
 57→    implements KeyValueStore<Bytes, byte[]>, CachedStateStore<byte[], byte[]> {
 58→
 59→    private static final Logger LOG = LoggerFactory.getLogger(CachingKeyValueStore.class);
 60→
 61→    private CacheFlushListener<byte[], byte[]> flushListener;
 62→    private boolean sendOldValues;
 63→    private String cacheName;
 64→    private InternalProcessorContext<?, ?> internalContext;
 65→    private Thread streamThread;
 66→    private final ReadWriteLock lock = new ReentrantReadWriteLock();
 67→    private final Position position;
 68→    private final CacheType cacheType;
 69→
 70→    @FunctionalInterface
 71→    public interface CacheQueryHandler {
 72→        QueryResult<?> apply(
 73→            final Query<?> query,
 74→            final Position mergedPosition,
 75→            final PositionBound positionBound,
 76→            final QueryConfig config,
 77→            final StateStore store
 78→        );
 79→    }
 80→
 81→    @SuppressWarnings("rawtypes")
 82→    private final Map<Class, CacheQueryHandler> queryHandlers =
 83→        mkMap(
 84→            mkEntry(
 85→                KeyQuery.class,
 86→                (query, mergedPosition, positionBound, config, store) ->
 87→                    runKeyQuery(query, mergedPosition, positionBound, config)
 88→            )
 89→        );
 90→
 91→
 92→    CachingKeyValueStore(final KeyValueStore<Bytes, byte[]> underlying, final CacheType cacheType) {
 93→        super(underlying);
 94→        position = Position.emptyPosition();
 95→        this.cacheType = cacheType;
 96→    }
 97→
 98→    @Override
 99→    public void init(final StateStoreContext stateStoreContext, final StateStore root) {
100→        internalContext = asInternalProcessorContext(stateStoreContext);
101→        cacheName = ThreadCache.nameSpaceFromTaskIdAndStore(internalContext.taskId().toString(), name());
102→        internalContext.registerCacheFlushListener(cacheName, entries -> {
103→            for (final ThreadCache.DirtyEntry entry : entries) {
104→                putAndMaybeForward(entry, internalContext);
105→            }
106→        });
107→        super.init(stateStoreContext, root);
108→        // save the stream thread as we only ever want to trigger a flush
109→        // when the stream thread is the current thread.
110→        streamThread = Thread.currentThread();
111→    }
112→
113→    @Override
114→    public Position getPosition() {
115→        // We return the merged position since the query uses the merged position as well
116→        final Position mergedPosition = Position.emptyPosition();
117→        final Position wrappedPosition = wrapped().getPosition();
118→        synchronized (position) {
119→            synchronized (wrappedPosition) {
120→                mergedPosition.merge(position);
121→                mergedPosition.merge(wrappedPosition);
122→            }
123→        }
124→        return mergedPosition;
125→    }
126→
127→    @SuppressWarnings("unchecked")
128→    @Override
129→    public <R> QueryResult<R> query(final Query<R> query,
130→                                    final PositionBound positionBound,
131→                                    final QueryConfig config) {
132→
133→        if (cacheType == CacheType.TIMESTAMPED_KEY_VALUE_STORE_WITH_HEADERS) {
134→            throw new UnsupportedOperationException("Queries (IQv2) are not supported for timestamped key-value stores with headers yet.");
135→        }
136→
137→        final long start = config.isCollectExecutionInfo() ? System.nanoTime() : -1L;
138→        final QueryResult<R> result;
139→
140→        final CacheQueryHandler handler = queryHandlers.get(query.getClass());
141→        if (handler == null) {
142→            result = wrapped().query(query, positionBound, config);
143→
144→        } else {
145→            final int partition = internalContext.taskId().partition();
146→            final Lock lock = this.lock.readLock();
147→            lock.lock();
148→            try {
149→                validateStoreOpen();
150→                final Position mergedPosition = getPosition();
151→
152→                // We use the merged position since the cache and the store may be at different positions
153→                if (!StoreQueryUtils.isPermitted(mergedPosition, positionBound, partition)) {
154→                    result = QueryResult.notUpToBound(mergedPosition, positionBound, partition);
155→                } else {
156→                    result = (QueryResult<R>) handler.apply(
157→                        query,
158→                        mergedPosition,
159→                        positionBound,
160→                        config,
161→                        this
162→                    );
163→                }
164→            } finally {
165→                lock.unlock();
166→            }
167→        }
168→        if (config.isCollectExecutionInfo()) {
169→            result.addExecutionInfo(
170→                "Handled in " + getClass() + " in " + (System.nanoTime() - start) + "ns");
171→        }
172→        return result;
173→    }
174→
175→    @SuppressWarnings("unchecked")
176→    private <R> QueryResult<R> runKeyQuery(final Query<R> query,
177→                                           final Position mergedPosition,
178→                                           final PositionBound positionBound,
179→                                           final QueryConfig config) {
180→        if (cacheType == CacheType.TIMESTAMPED_KEY_VALUE_STORE_WITH_HEADERS) {
181→            throw new UnsupportedOperationException("Queries (IQv2) are not supported for timestamped key-value stores with headers yet.");
182→        }
183→        QueryResult<R> result = null;
184→        final KeyQuery<Bytes, byte[]> keyQuery = (KeyQuery<Bytes, byte[]>) query;
185→
186→        if (keyQuery.isSkipCache()) {
187→            return wrapped().query(query, positionBound, config);
188→        }
189→
190→        final Bytes key = keyQuery.getKey();
191→
192→        synchronized (mergedPosition) {
193→            if (internalContext.cache() != null) {
194→                final LRUCacheEntry lruCacheEntry = internalContext.cache().get(cacheName, key);
195→                if (lruCacheEntry != null) {
196→                    final byte[] rawValue;
197→                    if (cacheType == CacheType.TIMESTAMPED_KEY_VALUE_STORE && !WrappedStateStore.isTimestamped(wrapped()) && !StoreQueryUtils.isAdapter(wrapped())) {
198→                        rawValue = ValueAndTimestampDeserializer.rawValue(lruCacheEntry.value());
199→                    } else {
200→                        rawValue = lruCacheEntry.value();
201→                    }
202→                    result = (QueryResult<R>) QueryResult.forResult(rawValue);
203→                }
204→            }
205→
206→            // We don't need to check the position at the state store since we already performed the check on
207→            // the merged position above
208→            if (result == null) {
209→                result = wrapped().query(query, PositionBound.unbounded(), config);
210→            }
211→            result.setPosition(mergedPosition.copy());
212→        }
213→        return result;
214→    }
215→
216→    private void putAndMaybeForward(final ThreadCache.DirtyEntry entry,
217→                                    final InternalProcessorContext<?, ?> context) {
218→        if (flushListener != null) {
219→            final byte[] rawNewValue = entry.newValue();
220→            final byte[] rawOldValue = rawNewValue == null || sendOldValues ? wrapped().get(entry.key()) : null;
221→
222→            // this is an optimization: if this key did not exist in underlying store and also not in the cache,
223→            // we can skip flushing to downstream as well as writing to underlying store
224→            if (rawNewValue != null || rawOldValue != null) {
225→                // we need to get the old values if needed, and then put to store, and then flush
226→                final ProcessorRecordContext current = context.recordContext();
227→                try {
228→                    context.setRecordContext(entry.entry().context());
229→                    wrapped().put(entry.key(), entry.newValue());
230→                    flushListener.apply(
231→                        new Record<>(
232→                            entry.key().get(),
233→                            new Change<>(rawNewValue, sendOldValues ? rawOldValue : null),
234→                            entry.entry().context().timestamp(),
235→                            entry.entry().context().headers()));
236→                } finally {
237→                    context.setRecordContext(current);
238→                }
239→            }
240→        } else {
241→            final ProcessorRecordContext current = context.recordContext();
242→            try {
243→                context.setRecordContext(entry.entry().context());
244→                wrapped().put(entry.key(), entry.newValue());
245→            } finally {
246→                context.setRecordContext(current);
247→            }
248→        }
249→    }
250→
251→    @Override
252→    public boolean setFlushListener(final CacheFlushListener<byte[], byte[]> flushListener,
253→                                    final boolean sendOldValues) {
254→        this.flushListener = flushListener;
255→        this.sendOldValues = sendOldValues;
256→
257→        return true;
258→    }
259→
260→    @Override
261→    public void put(final Bytes key,
262→                    final byte[] value) {
263→        Objects.requireNonNull(key, "key cannot be null");
264→        validateStoreOpen();
265→        lock.writeLock().lock();
266→        try {
267→            validateStoreOpen();
268→            // for null bytes, we still put it into cache indicating tombstones
269→            putInternal(key, value);
270→        } finally {
271→            lock.writeLock().unlock();
272→        }
273→    }
274→
275→    private void putInternal(final Bytes key,
276→                             final byte[] value) {
277→        synchronized (position) {
278→            internalContext.cache().put(
279→                cacheName,
280→                key,
281→                new LRUCacheEntry(
282→                    value,
283→                    internalContext.recordContext().headers(),
284→                    true,
285→                    internalContext.recordContext().offset(),
286→                    internalContext.recordContext().timestamp(),
287→                    internalContext.recordContext().partition(),
288→                    internalContext.recordContext().topic(),
289→                    internalContext.recordContext().sourceRawKey(),
290→                    internalContext.recordContext().sourceRawValue()
291→                )
292→            );
293→
294→            StoreQueryUtils.updatePosition(position, internalContext);
295→        }
296→    }
297→
298→    @Override
299→    public byte[] putIfAbsent(final Bytes key,
300→                              final byte[] value) {
301→        Objects.requireNonNull(key, "key cannot be null");
302→        validateStoreOpen();
303→        lock.writeLock().lock();
304→        try {
305→            validateStoreOpen();
306→            final byte[] v = getInternal(key);
307→            if (v == null) {
308→                putInternal(key, value);
309→            }
310→            return v;
311→        } finally {
312→            lock.writeLock().unlock();
313→        }
314→    }
315→
316→    @Override
317→    public void putAll(final List<KeyValue<Bytes, byte[]>> entries) {
318→        validateStoreOpen();
319→        lock.writeLock().lock();
320→        try {
321→            validateStoreOpen();
322→            for (final KeyValue<Bytes, byte[]> entry : entries) {
323→                Objects.requireNonNull(entry.key, "key cannot be null");
324→                put(entry.key, entry.value);
325→            }
326→        } finally {
327→            lock.writeLock().unlock();
328→        }
329→    }
330→
331→    @Override
332→    public byte[] delete(final Bytes key) {
333→        Objects.requireNonNull(key, "key cannot be null");
334→        validateStoreOpen();
335→        lock.writeLock().lock();
336→        try {
337→            validateStoreOpen();
338→            return deleteInternal(key);
339→        } finally {
340→            lock.writeLock().unlock();
341→        }
342→    }
343→
344→    private byte[] deleteInternal(final Bytes key) {
345→        final byte[] v = getInternal(key);
346→        putInternal(key, null);
347→        return v;
348→    }
349→
350→    @Override
351→    public byte[] get(final Bytes key) {
352→        Objects.requireNonNull(key, "key cannot be null");
353→        validateStoreOpen();
354→        final Lock theLock;
355→        if (Thread.currentThread().equals(streamThread)) {
356→            theLock = lock.writeLock();
357→        } else {
358→            theLock = lock.readLock();
359→        }
360→        theLock.lock();
361→        try {
362→            validateStoreOpen();
363→            return getInternal(key);
364→        } finally {
365→            theLock.unlock();
366→        }
367→    }
368→
369→    private byte[] getInternal(final Bytes key) {
370→        LRUCacheEntry entry = null;
371→        if (internalContext.cache() != null) {
372→            entry = internalContext.cache().get(cacheName, key);
373→        }
374→        if (entry == null) {
375→            final byte[] rawValue = wrapped().get(key);
376→            if (rawValue == null) {
377→                return null;
378→            }
379→            // only update the cache if this call is on the streamThread
380→            // as we don't want other threads to trigger an eviction/flush
381→            if (Thread.currentThread().equals(streamThread)) {
382→                internalContext.cache().put(cacheName, key, new LRUCacheEntry(rawValue));
383→            }
384→            return rawValue;
385→        } else {
386→            return entry.value();
387→        }
388→    }
389→
390→    @Override
391→    public KeyValueIterator<Bytes, byte[]> range(final Bytes from,
392→                                                 final Bytes to) {
393→        if (Objects.nonNull(from) && Objects.nonNull(to) && from.compareTo(to) > 0) {
394→            LOG.warn("Returning empty iterator for fetch with invalid key range: from > to. " +
395→                "This may be due to range arguments set in the wrong order, " +
396→                "or serdes that don't preserve ordering when lexicographically comparing the serialized bytes. " +
397→                "Note that the built-in numerical serdes do not follow this for negative numbers");
398→            return KeyValueIterators.emptyIterator();
399→        }
400→
401→        validateStoreOpen();
402→        final KeyValueIterator<Bytes, byte[]> storeIterator = wrapped().range(from, to);
403→        final ThreadCache.MemoryLRUCacheBytesIterator cacheIterator = internalContext.cache().range(cacheName, from, to);
404→        return new MergedSortedCacheKeyValueBytesStoreIterator(cacheIterator, storeIterator, true);
405→    }
406→
407→    @Override
408→    public KeyValueIterator<Bytes, byte[]> reverseRange(final Bytes from,
409→                                                        final Bytes to) {
410→        if (Objects.nonNull(from) && Objects.nonNull(to) && from.compareTo(to) > 0) {
411→            LOG.warn("Returning empty iterator for fetch with invalid key range: from > to. " +
412→                "This may be due to range arguments set in the wrong order, " +
413→                "or serdes that don't preserve ordering when lexicographically comparing the serialized bytes. " +
414→                "Note that the built-in numerical serdes do not follow this for negative numbers");
415→            return KeyValueIterators.emptyIterator();
416→        }
417→
418→        validateStoreOpen();
419→        final KeyValueIterator<Bytes, byte[]> storeIterator = wrapped().reverseRange(from, to);
420→        final ThreadCache.MemoryLRUCacheBytesIterator cacheIterator = internalContext.cache().reverseRange(cacheName, from, to);
421→        return new MergedSortedCacheKeyValueBytesStoreIterator(cacheIterator, storeIterator, false);
422→    }
423→
424→    @Override
425→    public KeyValueIterator<Bytes, byte[]> all() {
426→        validateStoreOpen();
427→        final KeyValueIterator<Bytes, byte[]> storeIterator = wrapped().all();
428→        final ThreadCache.MemoryLRUCacheBytesIterator cacheIterator = internalContext.cache().all(cacheName);
429→        return new MergedSortedCacheKeyValueBytesStoreIterator(cacheIterator, storeIterator, true);
430→    }
431→
432→    @Override
433→    public <PS extends Serializer<P>, P> KeyValueIterator<Bytes, byte[]> prefixScan(final P prefix, final PS prefixKeySerializer) {
434→        validateStoreOpen();
435→        final KeyValueIterator<Bytes, byte[]> storeIterator = wrapped().prefixScan(prefix, prefixKeySerializer);
436→        final Bytes from = Bytes.wrap(prefixKeySerializer.serialize(null, prefix));
437→        final Bytes to = Bytes.increment(from);
438→        final ThreadCache.MemoryLRUCacheBytesIterator cacheIterator = internalContext.cache().range(cacheName, from, to, false);
439→        return new MergedSortedCacheKeyValueBytesStoreIterator(cacheIterator, storeIterator, true);
440→    }
441→
442→    @Override
443→    public KeyValueIterator<Bytes, byte[]> reverseAll() {
444→        validateStoreOpen();
445→        final KeyValueIterator<Bytes, byte[]> storeIterator = wrapped().reverseAll();
446→        final ThreadCache.MemoryLRUCacheBytesIterator cacheIterator = internalContext.cache().reverseAll(cacheName);
447→        return new MergedSortedCacheKeyValueBytesStoreIterator(cacheIterator, storeIterator, false);
448→    }
449→
450→    @Override
451→    public long approximateNumEntries() {
452→        validateStoreOpen();
453→        lock.readLock().lock();
454→        try {
455→            validateStoreOpen();
456→            return wrapped().approximateNumEntries();
457→        } finally {
458→            lock.readLock().unlock();
459→        }
460→    }
461→
462→    @Override
463→    public void commit(final Map<TopicPartition, Long> changelogOffsets) {
464→        validateStoreOpen();
465→        lock.writeLock().lock();
466→        try {
467→            validateStoreOpen();
468→            internalContext.cache().flush(cacheName);
469→            wrapped().commit(changelogOffsets);
470→        } finally {
471→            lock.writeLock().unlock();
472→        }
473→    }
474→
475→    @Override
476→    public void flushCache() {
477→        validateStoreOpen();
478→        lock.writeLock().lock();
479→        try {
480→            validateStoreOpen();
481→            internalContext.cache().flush(cacheName);
482→        } finally {
483→            lock.writeLock().unlock();
484→        }
485→    }
486→
487→    @Override
488→    public void clearCache() {
489→        validateStoreOpen();
490→        lock.writeLock().lock();
491→        try {
492→            validateStoreOpen();
493→            internalContext.cache().clear(cacheName);
494→        } finally {
495→            lock.writeLock().unlock();
496→        }
497→    }
498→
499→    @Override
500→    public void close() {
501→        lock.writeLock().lock();
502→        try {
503→            final LinkedList<RuntimeException> suppressed = executeAll(
504→                () -> internalContext.cache().flush(cacheName),
505→                () -> internalContext.cache().close(cacheName),
506→                wrapped()::close
507→            );
508→            if (!suppressed.isEmpty()) {
509→                throwSuppressed("Caught an exception while closing caching key value store for store " + name(),
510→                    suppressed);
511→            }
512→        } finally {
513→            lock.writeLock().unlock();
514→        }
515→    }
516→
517→    public enum CacheType {
518→        KEY_VALUE_STORE,
519→        TIMESTAMPED_KEY_VALUE_STORE,
520→        TIMESTAMPED_KEY_VALUE_STORE_WITH_HEADERS
521→    }
522→}
