                }
                result.addAll(restoredActiveTasks);
                restoredActiveTasks.clear();
            } finally {
                restoredActiveTasksLock.unlock();
            }
            now = time.milliseconds();
        }
        return result;
    } catch (final InterruptedException ignored) {
    }
    return result;
}

