@Override
public void init(final StateStoreContext stateStoreContext,
                 final StateStore root) {
    if (root != null) {
        final boolean consistencyEnabled = StreamsConfig.InternalConfig.getBoolean(
            stateStoreContext.appConfigs(),
            IQ_CONSISTENCY_OFFSET_VECTOR_ENABLED,
            false
        );
        // register the store
        open = true;

        stateStoreContext.register(
            root,
            (RecordBatchingStateRestoreCallback) records -> {
                synchronized (InMemoryKeyValueStore.this) {
                    for (final ConsumerRecord<byte[], byte[]> record : records) {
                        putInternal(Bytes.wrap(record.key()), record.value());
                        ChangelogRecordDeserializationHelper.applyChecksAndUpdatePosition(
                            record,
                            consistencyEnabled,
                            position
                        );
                    }
                }
            }
        );
    }

    open = true;
    this.context = stateStoreContext;
}

@Override
public boolean persistent() {
    return false;
}

@Override
public boolean isOpen() {
    return open;
}

@Override
public Position getPosition() {
    return position;
}

@Override
public synchronized <R> QueryResult<R> query(final Query<R> query,
                                             final PositionBound positionBound,
                                             final QueryConfig config) {

    return StoreQueryUtils.handleBasicQueries(
        query,
        positionBound,
        config,
        this,
        position,
        context
    );
}

@Override
public synchronized byte[] get(final Bytes key) {
    return map.get(key);
}

@Override
public synchronized void put(final Bytes key, final byte[] value) {
    putInternal(key, value);
}

@Override
public synchronized byte[] putIfAbsent(final Bytes key, final byte[] value) {
    final byte[] originalValue = get(key);
    if (originalValue == null) {
        put(key, value);
    }
    return originalValue;
}

// the unlocked implementation of put method, to avoid multiple lock/unlock cost in `putAll` method
// caller must hold synchronized(this) to protect both map and position
private void putInternal(final Bytes key, final byte[] value) {
    if (value == null) {
        map.remove(key);
    } else {
        map.put(key, value);
    }

    StoreQueryUtils.updatePosition(position, context);
}

@Override
public synchronized void putAll(final List<KeyValue<Bytes, byte[]>> entries) {
    for (final KeyValue<Bytes, byte[]> entry : entries) {
        putInternal(entry.key, entry.value);
    }
}

