import org.apache.kafka.streams.query.QueryConfig;
import org.apache.kafka.streams.state.KeyValueStore;
import org.apache.kafka.streams.state.KeyValueStoreTestDriver;
import org.apache.kafka.streams.state.Stores;

/**
 * Fray test that exercises concurrent put() and query() on InMemoryKeyValueStore
 * to detect the deadlock caused by reversed lock ordering between
 * synchronized(this) and synchronized(position).
 */
public class InMemoryKeyValueStoreDeadlockTest {

    public static void main(final String[] args) throws Exception {
        final KeyValueStoreTestDriver<Bytes, byte[]> driver =
            KeyValueStoreTestDriver.create(Bytes.class, byte[].class);

        final KeyValueStore<Bytes, byte[]> store =
            Stores.keyValueStoreBuilder(
                Stores.inMemoryKeyValueStore("deadlock-test-store"),
                new Serdes.BytesSerde(),
                new Serdes.ByteArraySerde()
            ).withLoggingDisabled().build();

        store.init(driver.context(), store);

        final Bytes key = Bytes.wrap("key".getBytes());
        final byte[] value = "value".getBytes();

        // Seed the store so queries can find data
        store.put(key, value);

        final Thread writer = new Thread(() -> {
            for (int i = 0; i < 10; i++) {
                store.put(key, value);
            }
        });

        final Thread reader = new Thread(() -> {
            final KeyQuery<Bytes, byte[]> keyQuery = KeyQuery.withKey(key);
            final QueryConfig config = new QueryConfig(false);
            for (int i = 0; i < 10; i++) {
                store.query(keyQuery, PositionBound.unbounded(), config);
            }
        });

        writer.start();
        reader.start();

        writer.join();
        reader.join();

        store.close();
        driver.clear();
    }
}

